SELECT COUNT(request_id) 
FROM http_requests
WHERE source_ip = '192.168.1.1';

SELECT COUNT(DISTINCT client_id) 
FROM applications 
WHERE status = 'active';

SELECT idle_time 
FROM idle_times 
WHERE idle_time > 1000;

SELECT idle_time
FROM idle_times
WHERE request_id = 0;

SELECT COUNT(idle_time) 
FROM idle_times 
WHERE idle_time > (SELECT AVG(idle_time) FROM idle_times);
